// // This module converts a 4-bit binary number to a 4-bit gray code number on the falling edge of the clock signal.
module binary_to_gray(
    input [3:0] binary,
    input clk,
    output reg [3:0] gray
);

    always @(posedge clk) begin
        gray <= binary ^ (binary >> 1);
    end

endmodule
